import java.sql.*; public class T4 { public static void main(String[] a) throws Exception { Connection c = DriverManager.getConnection("jdbc:mysql://localhost:3306/symfony_db?useSSL=false&serverTimezone=UTC&allowPublicKeyRetrieval=true","root",""); ResultSet rs = c.createStatement().executeQuery("DESCRIBE users"); while(rs.next()) System.out.println(rs.getString(1)+" | "+rs.getString(2)); System.out.println("---MATCHING---"); ResultSet rs2 = c.createStatement().executeQuery("DESCRIBE matching_scores"); while(rs2.next()) System.out.println(rs2.getString(1)+" | "+rs2.getString(2)); System.out.println("---NOTES---"); ResultSet rs3 = c.createStatement().executeQuery("DESCRIBE candidature_notes"); while(rs3.next()) System.out.println(rs3.getString(1)+" | "+rs3.getString(2)); c.close(); } }